#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <string.h>

int main() {
    int fd[2];  // File descriptor for pipe
    const char* command = "cat";  // Command to run in the child process

    // Create a pipe
    if (pipe(fd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork a new process
    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    // Child process
    if (pid == 0) {
        // Close all unnecessary file descriptors
        close(fd[0]);  // Close read end of pipe

        // Redirect standard input and output to the pipe
        dup2(fd[1], STDOUT_FILENO);  // Redirect stdout to write end of pipe
        dup2(fd[1], STDIN_FILENO);   // Redirect stdin to write end of pipe

        // Close the write end of the pipe
        close(fd[1]);

        // Execute the command
